// 📌 CHECKOUT FINAL VERSION (QR + UI ĐẸP)
import React, { useState, useContext } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

import Header from "../components/common/Header";
import Navbar from "../components/common/Navbar";
import Footer from "../components/common/Footer";

import { CartContext } from "../context/CartContext";
import { AuthContext } from "../context/AuthContext";

import Select from "react-select";
import { FaUser, FaPhone, FaMapMarkerAlt, FaEnvelope } from "react-icons/fa";

const API_URL = "http://localhost:5000/api";

// Toàn bộ quận / huyện HCM
const districtOptions = [
  { value: "quan1", label: "Quận 1" },
  { value: "quan3", label: "Quận 3" },
  { value: "quan4", label: "Quận 4" },
  { value: "quan5", label: "Quận 5" },
  { value: "quan6", label: "Quận 6" },
  { value: "quan7", label: "Quận 7" },
  { value: "quan8", label: "Quận 8" },
  { value: "quan10", label: "Quận 10" },
  { value: "quan11", label: "Quận 11" },
  { value: "quan12", label: "Quận 12" },
  { value: "binhthanh", label: "Bình Thạnh" },
  { value: "govap", label: "Gò Vấp" },
  { value: "phunhuan", label: "Phú Nhuận" },
  { value: "tanbinh", label: "Tân Bình" },
  { value: "tanphu", label: "Tân Phú" },
  { value: "binhtan", label: "Bình Tân" },
  { value: "thuduc", label: "TP Thủ Đức" },
  { value: "binhchanh", label: "Huyện Bình Chánh" },
  { value: "hocmon", label: "Huyện Hóc Môn" },
  { value: "nhabe", label: "Huyện Nhà Bè" },
  { value: "cuchi", label: "Huyện Củ Chi" },
  { value: "cangio", label: "Huyện Cần Giờ" },
];

const Checkout = () => {
  const { cartItems, getCartTotal, clearCart } = useContext(CartContext);
  const { user } = useContext(AuthContext);
  const navigate = useNavigate();

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [paymentProof, setPaymentProof] = useState(null);

  const [formData, setFormData] = useState({
    fullName: user?.name || "",
    email: user?.email || "",
    phone: "",
    address: "",
    city: "hcm",
    district: "", // value của districtOptions
    notes: "",
    paymentMethod: "cod", // cod | bank | e_wallet
  });

  const shippingFee = getCartTotal() >= 500000 ? 0 : 30000;
  const finalTotal = getCartTotal() + shippingFee;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((p) => ({ ...p, [name]: value }));
  };

  const handleDistrictChange = (selected) => {
    setFormData((p) => ({ ...p, district: selected?.value || "" }));
  };

  const handleFileSelect = (file) => {
    if (file) setPaymentProof(file);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!user) return navigate("/login");

    if (
      !formData.fullName ||
      !formData.phone ||
      !formData.address ||
      !formData.district
    ) {
      return alert("⚠️ Vui lòng nhập đầy đủ thông tin giao hàng");
    }

    if (formData.paymentMethod !== "cod" && !paymentProof) {
      return alert("⚠️ Vui lòng upload ảnh xác nhận thanh toán!");
    }

    setLoading(true);
    setError("");

    try {
      const districtLabel =
        districtOptions.find((d) => d.value === formData.district)?.label || "";

      // 1️⃣ TẠO ĐƠN HÀNG
      const orderData = {
        orderItems: cartItems.map((item) => ({
          name: item.name,
          quantity: item.quantity,
          image: item.image || item.images?.[0],
          price: item.discountPrice || item.price,
          product: item._id,
        })),
        shippingAddress: {
          address: `${formData.address}, ${districtLabel}`,
          phone: formData.phone,
          city: "TP Hồ Chí Minh",
        },
        paymentMethod:
          formData.paymentMethod === "cod"
            ? "COD"
            : formData.paymentMethod === "bank"
            ? "BANK_TRANSFER"
            : "E_WALLET",
        totalPrice: finalTotal,
        notes: formData.notes,
      };

      const resOrder = await axios.post(`${API_URL}/orders`, orderData, {
        headers: { Authorization: `Bearer ${user.token}` },
      });

      const orderId = resOrder.data?.data?._id;

      // 2️⃣ UPLOAD ẢNH THANH TOÁN
      if (formData.paymentMethod !== "cod") {
        const uploadData = new FormData();
        uploadData.append("paymentProof", paymentProof);

        await axios.post(
          `${API_URL}/orders/upload-payment/${orderId}`,
          uploadData,
          {
            headers: {
              "Content-Type": "multipart/form-data",
              Authorization: `Bearer ${user.token}`,
            },
          }
        );
      }

      clearCart();
      navigate("/thank-you", { state: { orderId, customerInfo: formData } });
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "❌ Lỗi đặt hàng!");
    } finally {
      setLoading(false);
    }
  };

  if (!cartItems.length) {
    return (
      <div className="flex flex-col min-h-screen">
        <Header />
        <Navbar />
        <main className="flex-1 max-w-6xl mx-auto p-6">
          <div className="text-center p-8 bg-white rounded shadow">
            <p className="text-lg mb-4">Giỏ hàng trống</p>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen">
      <Header />
      <Navbar />

      <main className="flex-1 max-w-6xl mx-auto p-6">
        {error && (
          <div className="bg-red-100 p-3 text-red-700 rounded mb-4">
            {error}
          </div>
        )}

        <h1 className="text-3xl font-bold mb-6">Thanh toán</h1>

        <form
          onSubmit={handleSubmit}
          className="grid grid-cols-1 md:grid-cols-3 gap-6"
        >
          {/* LEFT: SHIPPING + PAYMENT */}
          <div className="md:col-span-2 bg-white p-6 shadow rounded">
            {/* 🔹 THÔNG TIN GIAO HÀNG */}
            <h2 className="text-xl font-bold mb-4">Thông tin giao hàng</h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Họ tên */}
              <div className="flex items-center gap-2 border rounded-lg px-3 py-2 bg-white focus-within:ring-2 focus-within:ring-pink-300">
                <FaUser className="text-gray-500 text-lg" />
                <input
                  type="text"
                  name="fullName"
                  placeholder="Họ và tên"
                  value={formData.fullName}
                  onChange={handleChange}
                  className="w-full outline-none bg-transparent"
                />
              </div>

              {/* Email */}
              <div className="flex items-center gap-2 border rounded-lg px-3 py-2 bg-white focus-within:ring-2 focus-within:ring-pink-300">
                <FaEnvelope className="text-gray-500 text-lg" />
                <input
                  type="email"
                  name="email"
                  placeholder="Email"
                  value={formData.email}
                  onChange={handleChange}
                  className="w-full outline-none bg-transparent"
                />
              </div>

              {/* Phone */}
              <div className="flex items-center gap-2 border rounded-lg px-3 py-2 bg-white focus-within:ring-2 focus-within:ring-pink-300">
                <FaPhone className="text-gray-500 text-lg" />
                <input
                  type="text"
                  name="phone"
                  placeholder="Số điện thoại"
                  value={formData.phone}
                  onChange={handleChange}
                  className="w-full outline-none bg-transparent"
                />
              </div>

              {/* District dropdown */}
              <div>
                <label className="text-gray-700 font-medium mb-1 block">
                  Quận / Huyện
                </label>
                <Select
                  classNamePrefix="react-select"
                  options={districtOptions}
                  placeholder="Chọn Quận/Huyện..."
                  value={
                    districtOptions.find(
                      (d) => d.value === formData.district
                    ) || null
                  }
                  onChange={handleDistrictChange}
                />
              </div>

              {/* Address full width */}
              <div className="md:col-span-2 flex items-center gap-2 border rounded-lg px-3 py-2 bg-white focus-within:ring-2 focus-within:ring-pink-300">
                <FaMapMarkerAlt className="text-gray-500 text-lg" />
                <input
                  type="text"
                  name="address"
                  placeholder="Ví dụ: 123 Nguyễn Trãi, P.7"
                  value={formData.address}
                  onChange={handleChange}
                  className="w-full outline-none bg-transparent"
                />
              </div>
            </div>

            {/* 🔹 PHƯƠNG THỨC THANH TOÁN */}
            <h2 className="text-xl font-bold mt-6 mb-3">
              Phương thức thanh toán
            </h2>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-4">
              {[
                { id: "cod", label: "🚚 Thanh toán khi nhận hàng" },
                { id: "bank", label: "🏦 Chuyển khoản ngân hàng" },
                { id: "e_wallet", label: "📱 Ví điện tử" },
              ].map((pm) => (
                <label
                  key={pm.id}
                  className={`flex items-center justify-center gap-2 border rounded-lg py-2 px-3 cursor-pointer text-sm transition 
                    ${
                      formData.paymentMethod === pm.id
                        ? "border-red-500 bg-red-50 text-red-600"
                        : "border-gray-300 hover:border-red-400"
                    }`}
                >
                  <input
                    type="radio"
                    name="paymentMethod"
                    value={pm.id}
                    checked={formData.paymentMethod === pm.id}
                    onChange={handleChange}
                    className="hidden"
                  />
                  <span>{pm.label}</span>
                </label>
              ))}
            </div>

            {/* BANK INFO + QR */}
            {formData.paymentMethod === "bank" && (
              <div className="mt-3 p-4 border rounded-lg bg-yellow-50">
                <h3 className="font-semibold mb-2">
                  Thông tin chuyển khoản ngân hàng
                </h3>
                <p>
                  <b>Ngân hàng:</b> VietTinBank
                </p>
                <p>
                  <b>STK:</b> 0383 654 182
                </p>
                <p>
                  <b>Tên:</b> DOAN THI MY DUYEN
                </p>
                <p>
                  <b>Nội dung chuyển khoản:</b>{" "}
                  {formData.phone || "SĐT của bạn"}
                </p>

                <div className="mt-3 text-center">
                  <p className="font-medium text-gray-700">
                    💳 Quét mã QR để thanh toán:
                  </p>
                  <img
                    className="w-48 mx-auto mt-2 rounded shadow border"
                    src={`https://img.vietqr.io/image/970436-0123456789-compact.png?amount=${finalTotal}&addInfo=${
                      formData.phone || "DDT Flower"
                    }`}
                    alt="QR Banking"
                  />
                </div>
              </div>
            )}

            {/* WALLET INFO + QR */}
            {formData.paymentMethod === "e_wallet" && (
              <div className="mt-3 p-4 border rounded-lg bg-purple-50">
                <h3 className="font-semibold mb-2">
                  Thanh toán ví điện tử (MoMo)
                </h3>
                <p>
                  <b>SĐT:</b> 0383 654 182
                </p>
                <p>
                  <b>Tên:</b> DOAN THI MY DUYEN
                </p>
                <div className="mt-3 text-center">
                  <p className="font-medium text-gray-700">
                    💳 Quét mã QR để thanh toán:
                  </p>
                  <img
                    className="w-48 mx-auto mt-2 rounded shadow border"
                    src={`https://img.vietqr.io/image/MOMO-0383654182-compact.png?amount=${finalTotal}&addInfo=${
                      formData.phone || "DDT Flower"
                    }`}
                    alt="QR MoMo"
                  />
                </div>
                <p className="text-sm text-gray-600 mt-2">
                  📌 Sau khi thanh toán, vui lòng chụp màn hình và tải lên bên
                  dưới.
                </p>
              </div>
            )}

            {/* FILE UPLOAD */}
            {formData.paymentMethod !== "cod" && (
              <div className="mt-4">
                <label className="font-medium block mb-1">
                  Ảnh xác nhận thanh toán *
                </label>
                <input
                  type="file"
                  accept="image/*"
                  onChange={(e) => handleFileSelect(e.target.files[0])}
                />
                {paymentProof && (
                  <p className="text-green-600 text-sm mt-1">
                    ✓ Đã chọn ảnh
                  </p>
                )}
              </div>
            )}

            <button
              type="submit"
              className="w-full bg-red-600 text-white py-3 rounded-lg text-lg font-bold mt-5 hover:bg-red-500 transition disabled:bg-gray-400"
              disabled={loading}
            >
              {loading
                ? "Đang xử lý..."
                : `Đặt hàng (${finalTotal.toLocaleString("vi-VN")}₫)`}
            </button>
          </div>

          {/* RIGHT: ORDER SUMMARY */}
          <div className="bg-white p-6 shadow rounded">
            <h2 className="font-bold text-lg mb-3">Đơn hàng</h2>
            {cartItems.map((item) => (
              <p
                key={item._id}
                className="flex justify-between border-b py-2 text-sm"
              >
                <span>
                  {item.name} × {item.quantity}
                </span>
                <span>
                  {(
                    (item.discountPrice || item.price) * item.quantity
                  ).toLocaleString("vi-VN")}
                  ₫
                </span>
              </p>
            ))}
            <p className="mt-3">
              Phí ship: {shippingFee ? "30.000₫" : "Miễn phí"}
            </p>
            <p className="text-red-600 font-bold mt-3 text-lg">
              Tổng: {finalTotal.toLocaleString("vi-VN")}₫
            </p>
          </div>
        </form>
      </main>

      <Footer />
    </div>
  );
};

export default Checkout;
